SELECT SUM(IFNULL(c.wages, 0)) wages, SUM(IFNULL(c.commission, 0)) commission, SUM(IFNULL(c.social_security, 0) + IFNULL(c.provident_fund, 0)) socialSecurity, SUM(IFNULL(c.evection_cost, 0)) evectionCost, SUM(IFNULL(c.evection_cost, 0) + IFNULL(c.other_cost, 0)) otherCost, count(1) personCount FROM t_rpt_base_cost c WHERE c.base_date = #{searchMonth}
and c.branch_cd in
#{item}
